macro_rules! parse_line {
    ($t: ty) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let a_str = a_str.trim();
        a_str.parse::<$t>().expect("parse error")
    });
    ($($t: ty),+) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let mut a_iter = a_str.split_whitespace();
        (
            $(
            a_iter.next().unwrap().parse::<$t>().expect("parse error"),
            )+
        )
    })
}

macro_rules! parse_line_to_vec {
    ($t: ty) => {{
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        (a_str
            .split_whitespace()
            .map(|x| x.parse::<$t>().unwrap())
            .collect::<Vec<$t>>())
    }};
}

fn solve() {
    let (n, m) = parse_line!(usize, usize);
    let l = parse_line_to_vec!(usize);
    let mut result = vec![0; n];
    let mut ok = true;
    for i in 1..m {
        let leader = l[i - 1] - 1;
        let mut diff = (n + l[i] - l[i - 1]) % n;
        if diff == 0 {
            diff = n;
        }
        if result[leader] == 0 {
            result[leader] = diff;
        }else if result[leader] != diff {
            ok = false;
        }
    }
    for i in 0..n {
        if result[i] == 0 {
            continue;
        }
        let mut local = true;
        for j in 0..i {
            local &= result[i] != result[j];
        }
        ok &= local;
    }
    if !ok {
        return println!("-1");
    }
    let mut s = std::collections::HashSet::<usize>::new();
    s.extend(result.iter());
    let mut next = 1;
    for i in 0..n {
        if result[i] != 0 {
            continue;
        }
        while s.contains(&next) {
            next += 1;
        }
        result[i] = next;
        next += 1;
    }
    for x in result {
        print!("{} ", x);
    }
    println!();
}

fn main() {
    let tests = 1; // parse_line!(usize);
    for _ in 0..tests {
        solve();
    }
}
